// Merge config from Master (body.config) or Sheet reads.
const webhookData = $('Webhook Trigger').first().json.body || {};

let config = {};

if (webhookData.config) {
  config = webhookData.config;
} else {
  try {
    const konfigRows = $('Konfig aus Sheet lesen').all();
    for (const row of konfigRows) {
      const key = (row.json['Einstellung'] || row.json['einstellung'] || '').trim();
      const val = (row.json['Wert'] || row.json['wert'] || '').trim();
      if (key) config[key] = val;
    }
  } catch (e) {
    // Sheet read may not have run (Master path)
  }
}

// Parse active platforms
const activePlatforms = (config.active_platforms || '')
  .split(',')
  .map(p => p.trim())
  .filter(p => p.length > 0);

// Parse active modules
const activeModules = (config.active_modules || '')
  .split(',')
  .map(m => m.trim())
  .filter(m => m.length > 0);

// Calendar week: use provided or compute
let calendarWeek = webhookData.calendar_week;
let year = webhookData.year;
if (!calendarWeek || !year) {
  const now = new Date();
  year = now.getFullYear();
  // ISO week calculation
  const jan1 = new Date(year, 0, 1);
  const days = Math.floor((now - jan1) / (24 * 60 * 60 * 1000));
  calendarWeek = Math.ceil((days + jan1.getDay() + 1) / 7);
}

return [{
  json: {
    config,
    projectName: config.project_name || 'unknown',
    brandName: config.brand_name || config.project_name || 'SocialPulse',
    brandColors: (config.brand_colors || '#1a73e8, #ffffff').split(',').map(c => c.trim()),
    brandTone: config.brand_tone || 'professionell, freundlich',
    activePlatforms,
    activeModules,
    hasMetaAds: activeModules.includes('meta_ads'),
    hasCompetitor: activeModules.includes('competitor'),
    hasContent: activeModules.includes('content'),
    calendarWeek: parseInt(calendarWeek),
    previousWeek: parseInt(calendarWeek) > 1 ? parseInt(calendarWeek) - 1 : 52,
    previousWeekYear: parseInt(calendarWeek) > 1 ? parseInt(year) : parseInt(year) - 1,
    fourWeekStart: parseInt(calendarWeek) > 4 ? parseInt(calendarWeek) - 4 : 52 + parseInt(calendarWeek) - 4,
    fourWeekStartYear: parseInt(calendarWeek) > 4 ? parseInt(year) : parseInt(year) - 1,
    year: parseInt(year),
    reportRecipients: (config.report_recipients || '').split(',').map(e => e.trim()).filter(e => e),
    reportCc: (config.report_cc || '').split(',').map(e => e.trim()).filter(e => e),
    timestamp: new Date().toISOString()
  }
}];

// =================================================================
// Consolidate all loaded data and compute WoW + 4-week averages
// =================================================================

const configData = $('Konfig zusammenfuehren').first().json;
const { projectName, brandName, calendarWeek, year, activePlatforms, hasMetaAds, hasCompetitor, hasContent } = configData;

// Helper: safely extract array from HTTP response
const safeArray = (nodeName) => {
  try {
    const items = $(nodeName).all();
    // Supabase GET returns array directly or wrapped
    if (items.length === 1 && Array.isArray(items[0].json)) {
      return items[0].json;
    }
    return items.map(i => i.json).filter(d => d && !d.error);
  } catch (e) {
    return [];
  }
};

const currentWeekData = safeArray('Performance aktuelle KW laden');
const previousWeekData = safeArray('Performance Vorwoche laden');
const fourWeekHistory = safeArray('Performance 4-Wochen-Historie laden');
const metaAdsData = safeArray('Meta Ads aktuelle KW laden');
const competitorData = safeArray('Competitor Insights laden');
const contentData = safeArray('Content-Vorschlaege laden');

// Helper: safely get number
const num = (v) => parseFloat(v) || 0;

// Helper: compute percentage change
const pctChange = (current, previous) => {
  if (previous === 0) return current > 0 ? 100 : 0;
  return Math.round(((current - previous) / previous) * 10000) / 100;
};

// Helper: trend arrow
const trendArrow = (change) => {
  if (change > 0) return { arrow: 'up', color: '#22c55e', symbol: '\u2191' };
  if (change < 0) return { arrow: 'down', color: '#ef4444', symbol: '\u2193' };
  return { arrow: 'flat', color: '#6b7280', symbol: '\u2192' };
};

// ---- Build platform performance comparisons ----
const platformReports = [];
const metrics = ['followers', 'follower_growth', 'posts_published', 'impressions', 'reach', 'likes', 'comments', 'shares', 'engagement_rate', 'video_views', 'story_views', 'link_clicks'];

for (const platform of activePlatforms) {
  const current = currentWeekData.find(d => d.platform === platform) || {};
  const previous = previousWeekData.find(d => d.platform === platform) || {};

  // 4-week history for this platform
  const history = fourWeekHistory.filter(d => d.platform === platform);

  // Compute 4-week averages
  const fourWeekAvg = {};
  for (const m of metrics) {
    const values = history.map(h => num(h[m])).filter(v => v > 0);
    fourWeekAvg[m] = values.length > 0 ? Math.round(values.reduce((a, b) => a + b, 0) / values.length * 100) / 100 : 0;
  }

  // Build comparison object
  const comparison = {};
  for (const m of metrics) {
    const currentVal = num(current[m]);
    const previousVal = num(previous[m]);
    const avgVal = fourWeekAvg[m];
    const change = pctChange(currentVal, previousVal);
    comparison[m] = {
      current: currentVal,
      previous: previousVal,
      fourWeekAvg: avgVal,
      changeWoW: change,
      changeVsAvg: pctChange(currentVal, avgVal),
      trend: trendArrow(change)
    };
  }

  platformReports.push({
    platform,
    hasCurrentData: Object.keys(current).length > 0,
    hasPreviousData: Object.keys(previous).length > 0,
    hasHistoryData: history.length > 0,
    topPostUrl: current.top_post_url || '',
    topPostEngagement: num(current.top_post_engagement),
    worstPostUrl: current.worst_post_url || '',
    worstPostEngagement: num(current.worst_post_engagement),
    comparison
  });
}

// ---- Cross-platform engagement ranking ----
const engagementRanking = platformReports
  .filter(p => p.hasCurrentData)
  .map(p => ({
    platform: p.platform,
    engagementRate: p.comparison.engagement_rate.current,
    impressions: p.comparison.impressions.current,
    reach: p.comparison.reach.current,
    totalEngagements: p.comparison.likes.current + p.comparison.comments.current + p.comparison.shares.current
  }))
  .sort((a, b) => b.engagementRate - a.engagementRate);

const bestPlatform = engagementRanking.length > 0 ? engagementRanking[0] : null;
const worstPlatform = engagementRanking.length > 0 ? engagementRanking[engagementRanking.length - 1] : null;

// ---- Cross-platform totals ----
const totalFollowers = platformReports.reduce((s, p) => s + p.comparison.followers.current, 0);
const totalImpressions = platformReports.reduce((s, p) => s + p.comparison.impressions.current, 0);
const totalReach = platformReports.reduce((s, p) => s + p.comparison.reach.current, 0);
const totalEngagements = platformReports.reduce((s, p) => s + p.comparison.likes.current + p.comparison.comments.current + p.comparison.shares.current, 0);
const avgEngagementRate = platformReports.length > 0
  ? Math.round(platformReports.reduce((s, p) => s + p.comparison.engagement_rate.current, 0) / platformReports.length * 10000) / 10000
  : 0;

// ---- Meta Ads summary (if available) ----
const metaAdsSummary = metaAdsData.length > 0 ? {
  available: true,
  totalSpend: num(metaAdsData[0].total_spend),
  totalImpressions: num(metaAdsData[0].total_impressions),
  totalClicks: num(metaAdsData[0].total_clicks),
  overallRoas: num(metaAdsData[0].overall_roas),
  overallCtr: num(metaAdsData[0].overall_ctr),
  overallCpc: num(metaAdsData[0].overall_cpc),
  top3Ads: metaAdsData[0].top_3_ads ? (typeof metaAdsData[0].top_3_ads === 'string' ? JSON.parse(metaAdsData[0].top_3_ads) : metaAdsData[0].top_3_ads) : [],
  analysisText: metaAdsData[0].analysis_text || ''
} : { available: false };

// ---- Competitor summary ----
const competitorSummary = competitorData.length > 0 ? {
  available: true,
  count: competitorData.length,
  items: competitorData.slice(0, 10).map(c => ({
    platform: c.platform,
    name: c.competitor_name || c.name,
    followers: num(c.followers),
    topPostEngagement: num(c.top_post_engagement),
    contentIdea: c.content_idea || c.content_idee || '',
    sentiment: c.sentiment || ''
  }))
} : { available: false };

// ---- Content suggestions summary ----
const contentSummary = contentData.length > 0 ? {
  available: true,
  count: contentData.length,
  items: contentData.slice(0, 10).map(c => ({
    platform: c.platform,
    type: c.content_type || c.typ || '',
    text: (c.text || '').substring(0, 200),
    status: c.status || 'Entwurf'
  }))
} : { available: false };

return [{
  json: {
    projectName,
    brandName,
    calendarWeek,
    year,
    previousWeek: configData.previousWeek,
    previousWeekYear: configData.previousWeekYear,
    activePlatforms,
    platformReports,
    crossPlatform: {
      engagementRanking,
      bestPlatform,
      worstPlatform,
      totalFollowers,
      totalImpressions,
      totalReach,
      totalEngagements,
      avgEngagementRate
    },
    metaAdsSummary,
    competitorSummary,
    contentSummary,
    dataQuality: {
      currentWeekPlatforms: currentWeekData.length,
      previousWeekPlatforms: previousWeekData.length,
      historyWeeks: [...new Set(fourWeekHistory.map(h => h.calendar_week))].length,
      hasMetaAds: metaAdsData.length > 0,
      hasCompetitorData: competitorData.length > 0,
      hasContentData: contentData.length > 0
    }
  }
}];

// Process Claude report analysis response
const consolidatedData = $('Daten konsolidieren + Vergleiche berechnen').first().json;
const claudeResponse = $input.first().json;

let reportNarrative = null;
let rawText = '';
let parseError = null;

try {
  // Claude API response: { content: [{ type: 'text', text: '...' }] }
  const content = claudeResponse.content;
  if (Array.isArray(content) && content.length > 0) {
    rawText = content[0].text || '';
  } else if (typeof claudeResponse === 'string') {
    rawText = claudeResponse;
  } else if (claudeResponse.error) {
    throw new Error('Claude API Fehler: ' + JSON.stringify(claudeResponse.error));
  }

  // Parse JSON (remove markdown fences if present)
  let cleanText = rawText.trim();
  if (cleanText.startsWith('```json')) {
    cleanText = cleanText.replace(/^```json\s*/, '').replace(/```\s*$/, '');
  } else if (cleanText.startsWith('```')) {
    cleanText = cleanText.replace(/^```\s*/, '').replace(/```\s*$/, '');
  }
  reportNarrative = JSON.parse(cleanText);
} catch (error) {
  parseError = error.message;
  // Fallback: create minimal narrative from data
  reportNarrative = {
    executive_summary: 'Der automatische Report fuer ' + consolidatedData.brandName + ' KW ' + consolidatedData.calendarWeek + '/' + consolidatedData.year + ' konnte nicht vollstaendig generiert werden. Bitte pruefen Sie die Rohdaten unten.',
    platform_performance: consolidatedData.activePlatforms.map(p => ({ platform: p, headline: 'Daten verfuegbar', highlights: ['Siehe KPI-Tabellen'], concerns: [], recommendation: 'Manuelle Analyse empfohlen.' })),
    cross_platform_comparison: { best_platform: consolidatedData.crossPlatform.bestPlatform?.platform || 'n/a', worst_platform: consolidatedData.crossPlatform.worstPlatform?.platform || 'n/a', key_insight: 'Automatische Analyse nicht verfuegbar.', engagement_trend: 'unbekannt', reach_trend: 'unbekannt' },
    meta_ads_performance: { available: consolidatedData.metaAdsSummary.available, summary: consolidatedData.metaAdsSummary.available ? 'Daten verfuegbar, manuelle Analyse empfohlen.' : 'Keine Meta Ads Daten.', top_ads_insight: '', budget_recommendation: '' },
    competitor_analysis: { available: consolidatedData.competitorSummary.available, key_findings: [], content_ideas: [] },
    content_recommendations: [],
    action_items: [{ priority: 'hoch', task: 'Claude-Analyse pruefen -- automatische Generierung fehlgeschlagen', reasoning: parseError }]
  };
}

return [{
  json: {
    ...consolidatedData,
    reportNarrative,
    claudeRawText: rawText,
    claudeParseError: parseError
  }
}];

// =================================================================
// Generate professional HTML report
// =================================================================

const data = $input.first().json;
const { brandName, calendarWeek, year, previousWeek, brandColors, platformReports, crossPlatform, metaAdsSummary, competitorSummary, contentSummary, reportNarrative } = data;

const primaryColor = (brandColors && brandColors[0]) || '#1a73e8';
const secondaryColor = (brandColors && brandColors[1]) || '#ffffff';

// Platform display names
const platformNames = {
  instagram: 'Instagram',
  facebook: 'Facebook',
  tiktok: 'TikTok',
  linkedin: 'LinkedIn',
  youtube: 'YouTube',
  x_twitter: 'X / Twitter'
};

// Platform icons (emoji fallback)
const platformIcons = {
  instagram: '&#x1F4F7;',
  facebook: '&#x1F4D8;',
  tiktok: '&#x1F3B5;',
  linkedin: '&#x1F4BC;',
  youtube: '&#x25B6;&#xFE0F;',
  x_twitter: '&#x1F426;'
};

// Helper: format number with locale
const fmt = (n) => (n === null || n === undefined) ? '-' : typeof n === 'number' ? n >= 1000000 ? (n / 1000000).toFixed(1) + 'M' : n >= 1000 ? (n / 1000).toFixed(1) + 'K' : n.toLocaleString('de-DE') : String(n);

// Helper: format percentage
const fmtPct = (n) => (n === null || n === undefined) ? '-' : ((v) => (v >= 0 ? '+' : '') + v.toFixed(2) + '%')(parseFloat(n));

// Helper: trend HTML
const trendHtml = (change) => change > 0 ? '<span style="color:#22c55e;font-weight:bold;">&#9650; ' + fmtPct(change) + '</span>' : change < 0 ? '<span style="color:#ef4444;font-weight:bold;">&#9660; ' + fmtPct(change) + '</span>' : '<span style="color:#6b7280;">&#9654; 0%</span>';

// Helper: priority badge
const priorityBadge = (p) => ((colors) => '<span style="background:' + (colors[p] || '#6b7280') + ';color:#fff;padding:2px 8px;border-radius:4px;font-size:12px;">' + (p || 'mittel').toUpperCase() + '</span>')({ hoch: '#ef4444', mittel: '#f59e0b', niedrig: '#22c55e' });

// ---- Build HTML ----
let html = '<!DOCTYPE html>\n<html lang="de">\n<head>\n<meta charset="UTF-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n<title>SocialPulse Report | ' + brandName + ' | KW ' + calendarWeek + '/' + year + '</title>\n<style>\n  * { margin: 0; padding: 0; box-sizing: border-box; }\n  body { font-family: -apple-system, BlinkMacSystemFont, \'Segoe UI\', Roboto, Oxygen, sans-serif; background: #f3f4f6; color: #1f2937; line-height: 1.6; }\n  .container { max-width: 800px; margin: 0 auto; background: #fff; }\n  .header { background: ' + primaryColor + '; color: ' + secondaryColor + '; padding: 32px 40px; }\n  .header h1 { font-size: 28px; margin-bottom: 4px; }\n  .header .subtitle { font-size: 16px; opacity: 0.9; }\n  .section { padding: 24px 40px; border-bottom: 1px solid #e5e7eb; }\n  .section-title { font-size: 20px; color: ' + primaryColor + '; margin-bottom: 16px; padding-bottom: 8px; border-bottom: 2px solid ' + primaryColor + '; }\n  .kpi-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(160px, 1fr)); gap: 12px; margin-bottom: 16px; }\n  .kpi-card { background: #f9fafb; border-radius: 8px; padding: 16px; text-align: center; border: 1px solid #e5e7eb; }\n  .kpi-value { font-size: 24px; font-weight: 700; color: #1f2937; }\n  .kpi-label { font-size: 12px; color: #6b7280; text-transform: uppercase; letter-spacing: 0.5px; margin-top: 4px; }\n  .kpi-trend { font-size: 13px; margin-top: 4px; }\n  table { width: 100%; border-collapse: collapse; margin: 12px 0; }\n  th { background: #f3f4f6; text-align: left; padding: 10px 12px; font-size: 13px; font-weight: 600; color: #4b5563; border-bottom: 2px solid #e5e7eb; }\n  td { padding: 10px 12px; border-bottom: 1px solid #e5e7eb; font-size: 14px; }\n  tr:last-child td { border-bottom: none; }\n  .platform-section { margin-bottom: 20px; background: #f9fafb; border-radius: 8px; padding: 20px; border-left: 4px solid ' + primaryColor + '; }\n  .platform-name { font-size: 18px; font-weight: 700; margin-bottom: 8px; }\n  .highlight { color: #059669; }\n  .concern { color: #dc2626; }\n  .bullet-list { padding-left: 20px; margin: 8px 0; }\n  .bullet-list li { margin-bottom: 4px; }\n  .action-item { display: flex; gap: 12px; align-items: flex-start; padding: 12px; background: #f9fafb; border-radius: 8px; margin-bottom: 8px; }\n  .action-priority { flex-shrink: 0; }\n  .action-text { flex: 1; }\n  .action-text strong { display: block; margin-bottom: 2px; }\n  .action-text small { color: #6b7280; }\n  .footer { padding: 20px 40px; background: #f3f4f6; text-align: center; font-size: 12px; color: #9ca3af; }\n  @media (max-width: 600px) {\n    .header, .section, .footer { padding-left: 20px; padding-right: 20px; }\n    .kpi-grid { grid-template-columns: repeat(2, 1fr); }\n  }\n</style>\n</head>\n<body>\n<div class="container">\n';

// HEADER
html += '<div class="header">\n  <h1>SocialPulse Report</h1>\n  <div class="subtitle">' + brandName + ' | KW ' + calendarWeek + '/' + year + ' (Vergleich: KW ' + previousWeek + ')</div>\n</div>\n';

// ---- SECTION 1: Executive Summary ----
html += '<div class="section">\n  <h2 class="section-title">1. Executive Summary</h2>\n  <p style="font-size:15px;line-height:1.7;">' + (reportNarrative.executive_summary || 'Keine Zusammenfassung verfuegbar.') + '</p>\n</div>\n';

// ---- Cross-Platform KPI Overview ----
html += '<div class="section">\n  <h2 class="section-title">Gesamt-KPIs (alle Plattformen)</h2>\n  <div class="kpi-grid">\n    <div class="kpi-card">\n      <div class="kpi-value">' + fmt(crossPlatform.totalFollowers) + '</div>\n      <div class="kpi-label">Followers gesamt</div>\n    </div>\n    <div class="kpi-card">\n      <div class="kpi-value">' + fmt(crossPlatform.totalImpressions) + '</div>\n      <div class="kpi-label">Impressions</div>\n    </div>\n    <div class="kpi-card">\n      <div class="kpi-value">' + fmt(crossPlatform.totalReach) + '</div>\n      <div class="kpi-label">Reach</div>\n    </div>\n    <div class="kpi-card">\n      <div class="kpi-value">' + fmt(crossPlatform.totalEngagements) + '</div>\n      <div class="kpi-label">Engagements</div>\n    </div>\n    <div class="kpi-card">\n      <div class="kpi-value">' + (crossPlatform.avgEngagementRate * 100).toFixed(2) + '%</div>\n      <div class="kpi-label">Avg. Engagement Rate</div>\n    </div>\n  </div>\n</div>\n';

// ---- SECTION 2: Platform Performance ----
html += '<div class="section">\n  <h2 class="section-title">2. Plattform-Performance</h2>\n';

for (const pr of platformReports) {
  const pName = platformNames[pr.platform] || pr.platform;
  const pIcon = platformIcons[pr.platform] || '';
  const narrative = (reportNarrative.platform_performance || []).find(p => p.platform === pr.platform) || {};
  const c = pr.comparison;

  html += '<div class="platform-section">\n    <div class="platform-name">' + pIcon + ' ' + pName + '</div>\n    <p style="margin-bottom:12px;">' + (narrative.headline || '') + '</p>\n    <table>\n      <tr><th>Metrik</th><th>KW ' + calendarWeek + '</th><th>KW ' + previousWeek + '</th><th>4-Wo. Avg</th><th>WoW</th></tr>\n      <tr><td>Followers</td><td>' + fmt(c.followers?.current) + '</td><td>' + fmt(c.followers?.previous) + '</td><td>' + fmt(c.followers?.fourWeekAvg) + '</td><td>' + trendHtml(c.followers?.changeWoW) + '</td></tr>\n      <tr><td>Impressions</td><td>' + fmt(c.impressions?.current) + '</td><td>' + fmt(c.impressions?.previous) + '</td><td>' + fmt(c.impressions?.fourWeekAvg) + '</td><td>' + trendHtml(c.impressions?.changeWoW) + '</td></tr>\n      <tr><td>Reach</td><td>' + fmt(c.reach?.current) + '</td><td>' + fmt(c.reach?.previous) + '</td><td>' + fmt(c.reach?.fourWeekAvg) + '</td><td>' + trendHtml(c.reach?.changeWoW) + '</td></tr>\n      <tr><td>Likes</td><td>' + fmt(c.likes?.current) + '</td><td>' + fmt(c.likes?.previous) + '</td><td>' + fmt(c.likes?.fourWeekAvg) + '</td><td>' + trendHtml(c.likes?.changeWoW) + '</td></tr>\n      <tr><td>Kommentare</td><td>' + fmt(c.comments?.current) + '</td><td>' + fmt(c.comments?.previous) + '</td><td>' + fmt(c.comments?.fourWeekAvg) + '</td><td>' + trendHtml(c.comments?.changeWoW) + '</td></tr>\n      <tr><td>Shares</td><td>' + fmt(c.shares?.current) + '</td><td>' + fmt(c.shares?.previous) + '</td><td>' + fmt(c.shares?.fourWeekAvg) + '</td><td>' + trendHtml(c.shares?.changeWoW) + '</td></tr>\n      <tr><td>Engagement Rate</td><td>' + (c.engagement_rate?.current * 100).toFixed(2) + '%</td><td>' + (c.engagement_rate?.previous * 100).toFixed(2) + '%</td><td>' + (c.engagement_rate?.fourWeekAvg * 100).toFixed(2) + '%</td><td>' + trendHtml(c.engagement_rate?.changeWoW) + '</td></tr>\n    </table>';

  if (narrative.highlights && narrative.highlights.length > 0) {
    html += '<p style="margin-top:8px;"><strong class="highlight">Highlights:</strong></p><ul class="bullet-list">';
    for (const h of narrative.highlights) { html += '<li>' + h + '</li>'; }
    html += '</ul>';
  }
  if (narrative.concerns && narrative.concerns.length > 0) {
    html += '<p><strong class="concern">Achtung:</strong></p><ul class="bullet-list">';
    for (const c2 of narrative.concerns) { html += '<li>' + c2 + '</li>'; }
    html += '</ul>';
  }
  if (narrative.recommendation) {
    html += '<p style="margin-top:8px;"><strong>Empfehlung:</strong> ' + narrative.recommendation + '</p>';
  }
  html += '</div>\n';
}
html += '</div>\n';

// ---- SECTION 3: Cross-Platform Comparison ----
const xp = reportNarrative.cross_platform_comparison || {};
html += '<div class="section">\n  <h2 class="section-title">3. Cross-Platform-Vergleich</h2>\n  <div class="kpi-grid">\n    <div class="kpi-card" style="border-left:4px solid #22c55e;">\n      <div class="kpi-label">Beste Plattform</div>\n      <div class="kpi-value" style="font-size:18px;">' + (platformNames[xp.best_platform] || xp.best_platform || '-') + '</div>\n    </div>\n    <div class="kpi-card" style="border-left:4px solid #ef4444;">\n      <div class="kpi-label">Schwaechste Plattform</div>\n      <div class="kpi-value" style="font-size:18px;">' + (platformNames[xp.worst_platform] || xp.worst_platform || '-') + '</div>\n    </div>\n    <div class="kpi-card">\n      <div class="kpi-label">Engagement-Trend</div>\n      <div class="kpi-value" style="font-size:18px;">' + (xp.engagement_trend || '-') + '</div>\n    </div>\n    <div class="kpi-card">\n      <div class="kpi-label">Reach-Trend</div>\n      <div class="kpi-value" style="font-size:18px;">' + (xp.reach_trend || '-') + '</div>\n    </div>\n  </div>\n  <p>' + (xp.key_insight || '') + '</p>\n  <table style="margin-top:12px;">\n    <tr><th>Plattform</th><th>Engagement Rate</th><th>Impressions</th><th>Reach</th></tr>';
for (const er of (crossPlatform.engagementRanking || [])) {
