const reportData = $('HTML-Report generieren').first().json;
const pdfResponse = $input.first().json;

const errors = [];

// Check Claude parse error
if (reportData.claudeParseError) {
  errors.push({
    source: 'claude_analysis',
    message: 'Claude-Analyse konnte nicht als JSON geparst werden: ' + reportData.claudeParseError
  });
}

// Check PDF generation
let pdfGenerated = false;
try {
  const binaryData = $input.first().binary;
  if (binaryData && binaryData.data) {
    pdfGenerated = true;
  }
} catch (e) {
  // No binary data
}
if (!pdfGenerated) {
  // Check if PDF API returned error
  if (pdfResponse && pdfResponse.error) {
    errors.push({
      source: 'pdf_generation',
      message: 'PDF-Generierung fehlgeschlagen: ' + JSON.stringify(pdfResponse.error)
    });
  } else if (!pdfResponse || typeof pdfResponse === 'object' && Object.keys(pdfResponse).length === 0) {
    errors.push({
      source: 'pdf_generation',
      message: 'PDF-Generierung: Keine Daten zurueckgegeben'
    });
  }
}

return [{
  json: {
    success: errors.length === 0,
    workflow: 'WF5 Report Generator',
    status: errors.length === 0 ? 'success' : 'partial_success',
    data: {
      reportSubject: reportData.reportSubject,
      calendarWeek: reportData.calendarWeek,
      year: reportData.year,
      brandName: reportData.brandName,
      platformsReported: reportData.activePlatforms,
      sectionsGenerated: 7,
      htmlLength: (reportData.htmlReport || '').length,
      pdfGenerated,
      reportRecipients: reportData.reportRecipients,
      reportCc: reportData.reportCc,
      crossPlatform: reportData.crossPlatform,
      dataQuality: reportData.dataQuality,
      // Pass full report data to WF6
      htmlReport: reportData.htmlReport,
      reportNarrative: reportData.reportNarrative
    },
    errors: errors.length > 0 ? errors : null,
    timestamp: new Date().toISOString()
  }
}];
